/// Phase-2 CRITICAL TEST GATE: the generated mutable-over-Map models
/// (`test/golden/test_messages.pb.dart`) round-trip through the `ball_protobuf`
/// runtime, and agree byte-for-byte / value-for-value with the conformance-pinned
/// dynamic codec.
///
/// The golden is generated by `tool/gen_golden.dart` from the checked-in
/// conformance `FileDescriptorSet`. Each test proves, for a representative
/// message:
///   (a) build via generated setters -> `toBytes()` equals `marshal()` of the
///       equivalent dynamic map against the same embedded descriptor;
///   (b) `fromBytes()` -> generated getters equal the dynamic `unmarshal()`;
///   (c) the proto3-JSON form matches `messageToJson()` and re-parses.
///
/// Coverage spans scalars, repeated, map, oneof, nested message, enum, and
/// optional/presence — across proto2, proto3, and edition2023.
@TestOn('vm')
library;

import 'dart:io';

import 'package:ball_protobuf/ball_protobuf.dart' as pb;
import 'package:ball_protobuf_gen/ball_protobuf_gen.dart';
import 'package:test/test.dart';

import '../tool/golden_format.dart';
import 'golden/test_messages.pb.dart' as gen;

void main() {
  group('proto3 TestAllTypesProto3', () {
    test(
      'scalars + repeated + enum: setters -> toBytes == dynamic marshal',
      () {
        final msg = gen.TestAllTypesProto3()
          ..optionalInt32 = 42
          ..optionalInt64 = 9007199254740991
          ..optionalUint32 = 7
          ..optionalString = 'hello'
          ..optionalBool = true
          ..optionalDouble = 3.5
          ..optionalBytes = [1, 2, 3]
          ..repeatedInt32 = [1, 2, 3]
          ..repeatedString = ['a', 'b']
          ..optionalNestedEnum = gen.TestAllTypesProto3_NestedEnum.bar;

        // Equivalent dynamic map (snake_case proto field names, scalar values).
        final dynamicMap = <String, Object?>{
          'optional_int32': 42,
          'optional_int64': 9007199254740991,
          'optional_uint32': 7,
          'optional_string': 'hello',
          'optional_bool': true,
          'optional_double': 3.5,
          'optional_bytes': [1, 2, 3],
          'repeated_int32': [1, 2, 3],
          'repeated_string': ['a', 'b'],
          'optional_nested_enum': 1, // BAR
        };

        final fromGenerated = msg.toBytes();
        final fromDynamic = pb.marshal(
          dynamicMap,
          gen.TestAllTypesProto3.descriptor,
        );
        expect(fromGenerated, fromDynamic);

        // (b) fromBytes -> getters equal the dynamic unmarshal.
        final decoded = gen.TestAllTypesProto3.fromBytes(fromGenerated);
        final dynDecoded = pb.unmarshal(
          fromDynamic,
          gen.TestAllTypesProto3.descriptor,
        );
        expect(decoded.optionalInt32, dynDecoded['optional_int32']);
        expect(decoded.optionalInt64, dynDecoded['optional_int64']);
        expect(decoded.optionalUint32, dynDecoded['optional_uint32']);
        expect(decoded.optionalString, dynDecoded['optional_string']);
        expect(decoded.optionalBool, dynDecoded['optional_bool']);
        expect(decoded.optionalDouble, dynDecoded['optional_double']);
        expect(decoded.optionalBytes, dynDecoded['optional_bytes']);
        expect(decoded.repeatedInt32, dynDecoded['repeated_int32']);
        expect(decoded.repeatedString, dynDecoded['repeated_string']);
        expect(
          decoded.optionalNestedEnum,
          gen.TestAllTypesProto3_NestedEnum.bar,
        );
      },
    );

    test('proto3 implicit presence: default value round-trips to nothing', () {
      final msg = gen.TestAllTypesProto3()..optionalInt32 = 0;
      // proto3 IMPLICIT presence elides the default on the wire.
      expect(msg.toBytes(), isEmpty);
      // Reading a never-set implicit field returns the type default.
      final fresh = gen.TestAllTypesProto3();
      expect(fresh.optionalInt32, 0);
      expect(fresh.optionalString, '');
      expect(fresh.optionalNestedEnum, gen.TestAllTypesProto3_NestedEnum.foo);
    });

    test('nested message round-trips', () {
      final msg = gen.TestAllTypesProto3()
        ..optionalNestedMessage = (gen.TestAllTypesProto3_NestedMessage()
          ..a = 99);
      final bytes = msg.toBytes();
      final decoded = gen.TestAllTypesProto3.fromBytes(bytes);
      expect(decoded.optionalNestedMessage, isNotNull);
      expect(decoded.optionalNestedMessage!.a, 99);

      // Matches the dynamic codec.
      final dyn = pb.unmarshal(bytes, gen.TestAllTypesProto3.descriptor);
      final nested = dyn['optional_nested_message'] as Map<String, Object?>;
      expect(nested['a'], 99);
    });

    test('recursive message round-trips (descriptor graph terminates)', () {
      final msg = gen.TestAllTypesProto3()
        ..recursiveMessage = (gen.TestAllTypesProto3()..optionalInt32 = 7);
      final decoded = gen.TestAllTypesProto3.fromBytes(msg.toBytes());
      expect(decoded.recursiveMessage, isNotNull);
      expect(decoded.recursiveMessage!.optionalInt32, 7);
    });

    test('map<string,int32> round-trips and matches dynamic marshal', () {
      final msg = gen.TestAllTypesProto3()
        ..mapStringString = {'k': 'v', 'x': 'y'};
      final fromGenerated = msg.toBytes();
      final fromDynamic = pb.marshal({
        'map_string_string': {'k': 'v', 'x': 'y'},
      }, gen.TestAllTypesProto3.descriptor);
      expect(fromGenerated, fromDynamic);

      final decoded = gen.TestAllTypesProto3.fromBytes(fromGenerated);
      expect(decoded.mapStringString, {'k': 'v', 'x': 'y'});
    });

    test('map<string,message> round-trips', () {
      final msg = gen.TestAllTypesProto3()
        ..mapStringNestedMessage = {
          'first': (gen.TestAllTypesProto3_NestedMessage()..a = 1),
          'second': (gen.TestAllTypesProto3_NestedMessage()..a = 2),
        };
      final decoded = gen.TestAllTypesProto3.fromBytes(msg.toBytes());
      final m = decoded.mapStringNestedMessage;
      expect(m.keys, containsAll(<String>['first', 'second']));
      expect(m['first']!.a, 1);
      expect(m['second']!.a, 2);
    });

    test('oneof: setting a member shows in whichX and clears siblings', () {
      final msg = gen.TestAllTypesProto3()..oneofUint32 = 5;
      expect(
        msg.whichOneofField,
        gen.TestAllTypesProto3_OneofFieldCase.oneofUint32,
      );

      // Setting a sibling field directly does not auto-clear in this
      // mutable-over-Map model, but the runtime enforces last-wins on the wire.
      // Decode picks the last set member.
      msg.oneofString = 'hi';
      // Both keys are present in the map; clearOneofField removes all members.
      msg.clearOneofField();
      expect(msg.whichOneofField, gen.TestAllTypesProto3_OneofFieldCase.notSet);

      // A single set member round-trips and is reported by whichX after decode.
      final m2 = gen.TestAllTypesProto3()..oneofString = 'pick-me';
      final decoded = gen.TestAllTypesProto3.fromBytes(m2.toBytes());
      expect(
        decoded.whichOneofField,
        gen.TestAllTypesProto3_OneofFieldCase.oneofString,
      );
      expect(decoded.oneofString, 'pick-me');
    });

    test('proto3 JSON matches messageToJson and re-parses', () {
      final msg = gen.TestAllTypesProto3()
        ..optionalInt32 = 11
        ..optionalString = 'json'
        ..repeatedInt32 = [4, 5]
        ..optionalNestedEnum = gen.TestAllTypesProto3_NestedEnum.baz;

      final genJson = msg.toProto3Json();
      final dynJson = pb.messageToJson({
        'optional_int32': 11,
        'optional_string': 'json',
        'repeated_int32': [4, 5],
        'optional_nested_enum': 2,
      }, gen.TestAllTypesProto3.descriptor);
      expect(genJson, dynJson);

      // lowerCamelCase keys, enum-as-name.
      final jsonMap = genJson as Map<String, Object?>;
      expect(jsonMap['optionalInt32'], 11);
      expect(jsonMap['optionalString'], 'json');
      expect(jsonMap['repeatedInt32'], [4, 5]);
      expect(jsonMap['optionalNestedEnum'], 'BAZ');

      final back = gen.TestAllTypesProto3.fromProto3Json(jsonMap);
      expect(back.optionalInt32, 11);
      expect(back.optionalString, 'json');
      expect(back.repeatedInt32, [4, 5]);
      expect(back.optionalNestedEnum, gen.TestAllTypesProto3_NestedEnum.baz);
    });

    test('WKT-typed fields round-trip via the runtime', () {
      // optional_duration is a google.protobuf.Duration field; build it via
      // the generated Duration model and prove binary + JSON round-trip.
      final dur = gen.Duration()
        ..seconds = 5
        ..nanos = 250000000;
      final msg = gen.TestAllTypesProto3()..optionalDuration = dur;

      final decoded = gen.TestAllTypesProto3.fromBytes(msg.toBytes());
      expect(decoded.optionalDuration, isNotNull);
      expect(decoded.optionalDuration!.seconds, 5);
      expect(decoded.optionalDuration!.nanos, 250000000);

      // JSON: Duration serializes to its seconds.nanos string form via the
      // runtime's WKT path (trailing zero groups trimmed).
      final json = msg.toProto3Json() as Map<String, Object?>;
      expect(json['optionalDuration'], '5.25s');
    });
  });

  group('proto2 TestAllTypesProto2', () {
    test('explicit presence: hasX / clearX track set state', () {
      final msg = gen.TestAllTypesProto2();
      expect(msg.hasOptionalInt32(), isFalse);
      msg.optionalInt32 = 0; // a default value, but explicitly set
      expect(msg.hasOptionalInt32(), isTrue);
      // EXPLICIT presence serializes even the default value.
      expect(msg.toBytes(), isNotEmpty);

      msg.clearOptionalInt32();
      expect(msg.hasOptionalInt32(), isFalse);
      expect(msg.toBytes(), isEmpty);
    });

    test('explicit-presence default value round-trips (proto2)', () {
      final msg = gen.TestAllTypesProto2()..optionalInt32 = 0;
      final bytes = msg.toBytes();
      // Matches the dynamic codec with the same embedded descriptor.
      final dyn = pb.marshal({
        'optional_int32': 0,
      }, gen.TestAllTypesProto2.descriptor);
      expect(bytes, dyn);

      final decoded = gen.TestAllTypesProto2.fromBytes(bytes);
      expect(decoded.hasOptionalInt32(), isTrue);
      expect(decoded.optionalInt32, 0);
    });

    test('expanded (unpacked) repeated scalars round-trip', () {
      final msg = gen.TestAllTypesProto2()..repeatedInt32 = [10, 20, 30];
      final fromGenerated = msg.toBytes();
      final fromDynamic = pb.marshal({
        'repeated_int32': [10, 20, 30],
      }, gen.TestAllTypesProto2.descriptor);
      expect(fromGenerated, fromDynamic);
      final decoded = gen.TestAllTypesProto2.fromBytes(fromGenerated);
      expect(decoded.repeatedInt32, [10, 20, 30]);
    });

    test('group (delimited) field round-trips', () {
      final msg = gen.TestAllTypesProto2()
        ..optionalString = 'g'
        ..data = (gen.TestAllTypesProto2_Data()..groupInt32 = 77);
      final decoded = gen.TestAllTypesProto2.fromBytes(msg.toBytes());
      expect(decoded.optionalString, 'g');
      expect(decoded.data, isNotNull);
      expect(decoded.data!.groupInt32, 77);
    });
  });

  group('proto2 TestAllRequiredTypesProto2 (LEGACY_REQUIRED)', () {
    test('required fields round-trip and are always serialized', () {
      // Set the two scalar required fields we exercise; required presence means
      // they serialize even at default and must survive a round-trip.
      final msg = gen.TestAllRequiredTypesProto2()
        ..requiredInt32 = 0
        ..requiredString = 'req';
      final bytes = msg.toBytes();
      final dyn = pb.unmarshal(
        bytes,
        gen.TestAllRequiredTypesProto2.descriptor,
      );
      expect(dyn['required_int32'], 0);
      expect(dyn['required_string'], 'req');

      final decoded = gen.TestAllRequiredTypesProto2.fromBytes(bytes);
      expect(decoded.hasRequiredInt32(), isTrue);
      expect(decoded.requiredString, 'req');
    });
  });

  group('edition2023 TestAllTypesEdition2023', () {
    test('explicit presence (editions default) + scalars round-trip', () {
      final msg = gen.TestAllTypesEdition2023()
        ..optionalInt32 = 5
        ..optionalString = 'ed';
      // EDITION_2023 default presence is EXPLICIT, so hasX is generated.
      expect(msg.hasOptionalInt32(), isTrue);

      final fromGenerated = msg.toBytes();
      final fromDynamic = pb.marshal({
        'optional_int32': 5,
        'optional_string': 'ed',
      }, gen.TestAllTypesEdition2023.descriptor);
      expect(fromGenerated, fromDynamic);

      final decoded = gen.TestAllTypesEdition2023.fromBytes(fromGenerated);
      expect(decoded.optionalInt32, 5);
      expect(decoded.optionalString, 'ed');
    });

    test('edition2023 enum field round-trips', () {
      final msg = gen.TestAllTypesEdition2023()
        ..optionalNestedEnum = gen.TestAllTypesEdition2023_NestedEnum.bar;
      final decoded = gen.TestAllTypesEdition2023.fromBytes(msg.toBytes());
      expect(
        decoded.optionalNestedEnum,
        gen.TestAllTypesEdition2023_NestedEnum.bar,
      );
    });

    test('edition2023 packed repeated + map round-trip', () {
      final msg = gen.TestAllTypesEdition2023()
        ..packedInt32 = [1, 2, 3]
        ..mapInt32Int32 = {1: 10, 2: 20};
      final decoded = gen.TestAllTypesEdition2023.fromBytes(msg.toBytes());
      expect(decoded.packedInt32, [1, 2, 3]);
      expect(decoded.mapInt32Int32, {1: 10, 2: 20});
    });
  });

  group('golden drift guard', () {
    test('committed golden matches a fresh regeneration', () {
      final fds = File(_findDescriptorSet()).readAsBytesSync();
      final regenerated = formatGolden(
        generateCombinedDartFile(
          fds,
          outputPath: 'test_messages.pb.dart',
        ).content,
      );
      final committed = File(
        '${_packageRoot()}/test/golden/test_messages.pb.dart',
      ).readAsStringSync().replaceAll('\r\n', '\n');
      expect(
        regenerated.replaceAll('\r\n', '\n'),
        committed,
        reason: 'Run `dart run tool/gen_golden.dart` to refresh the golden.',
      );
    });
  });
}

String _packageRoot() {
  var dir = Directory.current;
  for (var i = 0; i < 8; i++) {
    if (File('${dir.path}/pubspec.yaml').existsSync() &&
        Directory('${dir.path}/lib/src').existsSync()) {
      return dir.path;
    }
    final parent = dir.parent;
    if (parent.path == dir.path) break;
    dir = parent;
  }
  return Directory.current.path;
}

String _findDescriptorSet() {
  const rel = 'tests/editions/descriptors/test_messages.fds.binpb';
  var dir = Directory.current;
  for (var i = 0; i < 8; i++) {
    final f = File('${dir.path}/$rel');
    if (f.existsSync()) return f.path;
    final parent = dir.parent;
    if (parent.path == dir.path) break;
    dir = parent;
  }
  throw StateError('Could not locate $rel from ${Directory.current.path}');
}
